// Extract token usage from all AI nodes in the execution
const execData = $json;
const runData = execData?.data?.resultData?.runData || {};
const workflowId = execData?.workflowData?.id || '';
const workflowName = $('workflow_trigger').first().json.source_workflow_name || execData?.workflowData?.name || '';
const executionId = $('workflow_trigger').first().json.execution_id || '';

// Build a model map from workflow node definitions
const nodeModelMap = {};
for (const node of (execData?.workflowData?.nodes || [])) {
  const params = node.parameters || {};
  let model = '';
  if (params.model) {
    model = typeof params.model === 'object' ? (params.model.value || params.model.cachedResultName || '') : params.model;
  }
  if (params.modelName) {
    model = typeof params.modelName === 'string' ? params.modelName : (params.modelName.value || '');
  }
  if (model) {
    // Clean model name
    model = model.replace('models/', '');
    nodeModelMap[node.name] = model;
  }
}

const records = [];

// Pricing per 1M tokens
const pricing = {
  'claude-sonnet-4-20250514': { input: 3.0, output: 15.0, provider: 'anthropic' },
  'claude-sonnet-4-6-20250514': { input: 3.0, output: 15.0, provider: 'anthropic' },
  'claude-3-5-sonnet': { input: 3.0, output: 15.0, provider: 'anthropic' },
  'gemini-2.5-pro': { input: 1.25, output: 10.0, provider: 'google' },
  'gemini-2.5-flash': { input: 0.15, output: 0.60, provider: 'google' },
  'gpt-4o': { input: 2.50, output: 10.0, provider: 'openai' },
  'gpt-4o-mini': { input: 0.15, output: 0.60, provider: 'openai' },
  'text-embedding-3-small': { input: 0.02, output: 0, provider: 'openai' },
  'sonar': { input: 1.0, output: 1.0, provider: 'perplexity' },
  'sonar-pro': { input: 3.0, output: 15.0, provider: 'perplexity' },
};

function getPrice(model) {
  if (!model) return { input: 1.0, output: 1.0, provider: 'unknown' };
  const m = model.toLowerCase();
  for (const [key, val] of Object.entries(pricing)) {
    if (m.includes(key) || key.includes(m)) return val;
  }
  if (m.includes('claude') || m.includes('anthropic')) return { input: 3.0, output: 15.0, provider: 'anthropic' };
  if (m.includes('gemini')) return { input: 1.25, output: 10.0, provider: 'google' };
  if (m.includes('gpt')) return { input: 2.50, output: 10.0, provider: 'openai' };
  if (m.includes('sonar') || m.includes('perplexity')) return { input: 1.0, output: 1.0, provider: 'perplexity' };
  return { input: 1.0, output: 1.0, provider: 'unknown' };
}

for (const [nodeName, nodeRuns] of Object.entries(runData)) {
  for (const run of nodeRuns) {
    const llmData = run?.data?.ai_languageModel;
    if (llmData) {
      for (const outputs of llmData) {
        for (const item of outputs) {
          const j = item?.json || {};
          const tokenUsage = j.tokenUsage || j.tokenUsageEstimate || {};

          // Get model name — check multiple locations
          let modelName = '';

          // 1. inputOverride.ai_languageModel[0][0].json.options.model (most reliable)
          const io = run?.inputOverride?.ai_languageModel;
          if (io && io[0] && io[0][0]) {
            const ioOpts = io[0][0]?.json?.options || {};
            modelName = ioOpts.model || ioOpts.model_name || ioOpts.modelName || '';
          }

          // 2. generationInfo.model_name
          if (!modelName) {
            const gi = j?.response?.generations?.[0]?.[0]?.generationInfo || {};
            modelName = gi.model_name || gi.model || '';
          }

          // 3. Workflow node definition
          if (!modelName) {
            modelName = nodeModelMap[nodeName] || '';
          }

          // 4. Infer from node name
          if (!modelName) {
            if (nodeName.toLowerCase().includes('gemini')) modelName = 'gemini-2.5-pro';
            else if (nodeName.toLowerCase().includes('claude') || nodeName.toLowerCase().includes('sonnet')) modelName = 'claude-sonnet-4-20250514';
            else if (nodeName.toLowerCase().includes('gpt') || nodeName.toLowerCase().includes('openai')) modelName = 'gpt-4o';
          }

          // Clean model name
          modelName = modelName.replace('models/', '');

          if (tokenUsage.promptTokens || tokenUsage.completionTokens || tokenUsage.totalTokens) {
            const prompt_t = tokenUsage.promptTokens || 0;
            const completion_t = tokenUsage.completionTokens || 0;
            const total_t = tokenUsage.totalTokens || (prompt_t + completion_t);
            const priceInfo = getPrice(modelName);
            const cost = (prompt_t * priceInfo.input / 1000000) + (completion_t * priceInfo.output / 1000000);

            records.push({
              execution_id: executionId,
              workflow_id: workflowId,
              workflow_name: workflowName,
              node_name: nodeName,
              provider: priceInfo.provider,
              llm_model: modelName || 'unknown',
              prompt_tokens: prompt_t,
              completion_tokens: completion_t,
              total_tokens: total_t,
              estimated_cost: Math.round(cost * 1000000) / 1000000
            });
          }
        }
      }
    }

    // Perplexity nodes
    const mainData = run?.data?.main;
    if (mainData && (nodeName.toLowerCase().includes('perplexity') || nodeName.toLowerCase().includes('research'))) {
      for (const outputs of (mainData || [])) {
        for (const item of (outputs || [])) {
          const usage = item?.json?.usage;
          if (usage && (usage.prompt_tokens || usage.completion_tokens)) {
            const prompt_t = usage.prompt_tokens || 0;
            const completion_t = usage.completion_tokens || 0;
            const total_t = prompt_t + completion_t;
            const model = item?.json?.model || 'sonar';
            const priceInfo = getPrice(model);
            const cost = (prompt_t * priceInfo.input / 1000000) + (completion_t * priceInfo.output / 1000000);

            records.push({
              execution_id: executionId,
              workflow_id: workflowId,
              workflow_name: workflowName,
              node_name: nodeName,
              provider: 'perplexity',
              llm_model: model,
              prompt_tokens: prompt_t,
              completion_tokens: completion_t,
              total_tokens: total_t,
              estimated_cost: Math.round(cost * 1000000) / 1000000
            });
          }
        }
      }
    }
  }
}

if (records.length === 0) {
  return [{ json: { result: 'No token usage found in execution ' + executionId, records: 0 } }];
}

return records.map(r => ({ json: r }));

// Save aggregated token usage to Supabase
const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_KEY = 'REDACTED_SUPABASE_KEY';
const items = $input.all();

const rows = items.map(item => ({
  execution_id: item.json.execution_id || '',
  workflow_id: item.json.workflow_id || '',
  workflow_name: item.json.workflow_name || '',
  llm_model: item.json.llm_model || '',
  provider: item.json.provider || '',
  prompt_tokens: item.json.sum_prompt_tokens || 0,
  completion_tokens: item.json.sum_completion_tokens || 0,
  total_tokens: item.json.sum_total_tokens || 0,
  estimated_cost: item.json.sum_estimated_cost || 0
}));

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/token_usage_v2',
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': 'Bearer ' + SUPABASE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify(rows)
  });
} catch(e) {
  // Table might not exist yet — that's ok, log the data anyway
  return [{ json: { error: true, result: 'Could not save to Supabase: ' + e.message, records: rows.length, data: rows } }];
}

return [{ json: { result: 'Saved ' + rows.length + ' token usage records', records: rows.length } }];

